from collections import deque
class Solution:
    def pathExistenceQueries(self, n, nums, maxDiff, queries):
        adj = [[] for _ in range(n)]
        for i in range(n):
            for j in range(i + 1, n):
                if abs(nums[i] - nums[j]) <= maxDiff:
                    adj[i].append(j)
                    adj[j].append(i)
        ans = []
        for u, v in queries:
            if u == v:
                ans.append(0)
                continue
            dist = [-1] * n
            dist[u] = 0
            dq = deque([u])
            while dq:
                x = dq.popleft()
                for y in adj[x]:
                    if dist[y] == -1:
                        dist[y] = dist[x] + 1
                        dq.append(y)
            ans.append(dist[v])
        return ans

