var pathExistenceQueries = function(n, nums, maxDiff, queries) {
    const order = Array.from({ length: n }, (_, i) => i);
    order.sort((a, b) => nums[a] - nums[b]);
    const pos = new Array(n);
    const sv = new Array(n);
    for (let p = 0; p < n; p++) { pos[order[p]] = p; sv[p] = nums[order[p]]; }
    const ans = [];
    for (const [u, v] of queries) {
        const pu = pos[u], pv = pos[v];
        if (pu === pv) { ans.push(0); continue; }
        const lo = Math.min(pu, pv), hi = Math.max(pu, pv);
        let steps = 0, curLo = lo, curHi = lo, reached = false;
        while (true) {
            if (curLo <= hi && hi <= curHi) { reached = true; break; }
            const left = lowerBound(sv, sv[curLo] - maxDiff);
            const right = upperBound(sv, sv[curHi] + maxDiff) - 1;
            if (left === curLo && right === curHi) break;
            curLo = left; curHi = right; steps++;
        }
        ans.push(reached ? steps : -1);
    }
    return ans;
};
